draw(O--B,Arrow(6));
draw(O--C,Arrow(6));
draw(interp(A,C,-0.1)--interp(A,C,1.1),dashed);

label("$\mathbf{a}$", A, NE);
label("$\mathbf{b}$", B, NE);
label("$\mathbf{c}$", C, NE);
[/asy]

